#include <stdio.h>
#include <stdlib.h>

// Node structure for queue
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Queue structure
typedef struct Queue {
    Node* front;
    Node* rear;
} Queue;

// Function to create a new node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to create a queue
Queue* createQueue() {
    Queue* q = (Queue*) malloc(sizeof(Queue));
    if (!q) {
        printf("Memory error\n");
        return NULL;
    }
    q->front = q->rear = NULL;
    return q;
}

// Function to check if the queue is empty
int isEmpty(Queue* q) {
    return (q->front == NULL);
}

// Function to add an element to the queue
void enqueue(Queue* q, int data) {
    Node* temp = createNode(data);
    if (q->rear) {
        q->rear->next = temp;
        q->rear = temp;
    } else {
        q->front = q->rear = temp;
    }
}

// Function to remove an element from the queue
int dequeue(Queue* q) {
    if (isEmpty(q)) {
        printf("Queue is empty\n");
        return -1;
    }
    Node* temp = q->front;
    int data = temp->data;
    q->front = temp->next;
    if (q->front == NULL) {
        q->rear = NULL;
    }
    free(temp);
    return data;
}

// Function to get the front element of the queue
int front(Queue* q) {
    if (isEmpty(q)) {
        printf("Queue is empty\n");
        return -1;
    }
    return q->front->data;
}

// Stack implementation using Queue
typedef struct Stack {
    Queue* q;
} Stack;

// Function to create a stack
Stack* createStack() {
    Stack* s = (Stack*) malloc(sizeof(Stack));
    if (!s) {
        printf("Memory error\n");
        return NULL;
    }
    s->q = createQueue();
    return s;
}

// Function to push an element onto the stack
void push(Stack* s, int data) {
    enqueue(s->q, data);
    for (int i = 0; i < size(s->q) - 1; i++) {
        enqueue(s->q, dequeue(s->q));
    }
}

// Function to pop an element from the stack
int pop(Stack* s) {
    return dequeue(s->q);
}

// Function to get the top element of the stack
int top(Stack* s) {
    return front(s->q);
}

// Function to check if the stack is empty
int isEmptyStack(Stack* s) {
    return isEmpty(s->q);
}

// Function to get the size of the queue
int size(Queue* q) {
    int count = 0;
    Node* temp = q->front;
    while (temp) {
        count++;
        temp = temp->next;
    }
    return count;
}

int main() {
    Stack* s = createStack();
    // List of commands
    char* commands[] = {"QueueStack", "push", "push", "pop", "top", "isEmpty"};
    // List of inputs
    int inputs[][10] = {{}, {4}, {8}, {}, {}, {}};

    for (int i = 0; i < 6; ++i) {
        if (strcmp(commands[i], "push") == 0) {
            push(s, inputs[i][0]);
            printf("null ");
        } else if (strcmp(commands[i], "pop") == 0) {
            printf("%d ", pop(s));
        } else if (strcmp(commands[i], "top") == 0) {
            printf("%d ", top(s));
        } else if (strcmp(commands[i], "isEmpty") == 0) {
            printf("%d ", isEmptyStack(s));
        } else if (strcmp(commands[i], "QueueStack") == 0) {
            printf("null ");
        }
    }

    return 0;
}

